        private static P0AssetManifestEntry Entry(
            string assetId,
            string subjectId,
            string assetType,
            string sourcePromptPath,
            IReadOnlyList<string> referenceAssetIds,
            string unityImportPath,
            string size,
            string consistencyNotes,
            string status = P0AssetManifestStatus.Planned,
            IReadOnlyList<string> sourceLockIds = null)
        {
            return new P0AssetManifestEntry(
                assetId,
                subjectId,
                assetType,
                "P0",
                sourcePromptPath,
                referenceAssetIds,
                sourceLockIds,
                unityImportPath,
                size,
                status,
                consistencyNotes);
        }

        private static IReadOnlyList<string> Empty()
        {
            return new string[0];
        }

        private static IReadOnlyList<string> Ref(string assetId)
        {
            return new[] { assetId };
        }

        private static IReadOnlyList<string> Refs(params string[] assetIds)
        {
            return assetIds ?? Empty();
        }

        private static IReadOnlyList<string> Locks(params string[] lockIds)
        {
            return lockIds ?? Empty();
        }
